// nodes/llmNode.js
import { BaseNode } from '../components/BaseNode';

const config = {
  title: 'LLM',
  icon: '🤖',
  color: 'var(--pf-purple)',
  fields: [
    { key: 'model', label: 'Model', type: 'select', defaultValue: 'gpt-4o',
      options: ['gpt-4o', 'gpt-4-turbo', 'gpt-3.5-turbo', 'claude-3-5-sonnet', 'gemini-pro'] },
    { key: 'temperature', label: 'Temperature', type: 'text', defaultValue: '0.7', placeholder: '0.0 – 1.0' },
  ],
  inputs:  [
    { id: 'system', label: 'System' },
    { id: 'prompt', label: 'Prompt' },
  ],
  outputs: [{ id: 'response', label: 'Response' }],
};

export const LLMNode = (props) => <BaseNode {...props} config={config} />;
